import{M as e,d as t,h as n}from"./chunks/runtime-core.esm-bundler.Di_optew.js";import{t as r}from"./chunks/plugin-vue_export-helper.B_ZXV7eh.js";var i=JSON.parse(`{"title":"Project Philosophy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/philosophy.md","filePath":"guide/philosophy.md"}`),a={name:`guide/philosophy.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide\\philosophy.md for this page in Markdown format</div><h1 id="project-philosophy" tabindex="-1">Project Philosophy <a class="header-anchor" href="#project-philosophy" aria-label="Permalink to “Project Philosophy”">​</a></h1><h2 id="lean-extendable-core" tabindex="-1">Lean Extendable Core <a class="header-anchor" href="#lean-extendable-core" aria-label="Permalink to “Lean Extendable Core”">​</a></h2><p>Vite aims to support the most common patterns to build Web apps out-of-the-box, while keeping <a href="https://github.com/vitejs/vite" target="_blank" rel="noreferrer">Vite core</a> lean and maintainable long-term. We believe the best way to support diverse use cases is to provide strong primitives and APIs that plugins can build on, and we actively expand the core to make Vite more extensible. <a href="./api-plugin">Vite&#39;s plugin system</a> is based on a superset of Rollup&#39;s plugin API, and it enables plugins like <a href="https://vite-pwa-org.netlify.app/" target="_blank" rel="noreferrer">vite-plugin-pwa</a> and the many <a href="https://registry.vite.dev/plugins" target="_blank" rel="noreferrer">well maintained plugins</a> available to cover your needs. Vite&#39;s bundler, <a href="https://rolldown.rs/" target="_blank" rel="noreferrer">Rolldown</a>, maintains compatibility with Rollup&#39;s plugin interface, so plugins can often be used across both Vite and plain Rollup projects.</p><h2 id="pushing-the-modern-web" tabindex="-1">Pushing the Modern Web <a class="header-anchor" href="#pushing-the-modern-web" aria-label="Permalink to “Pushing the Modern Web”">​</a></h2><p>Vite provides opinionated features that push writing modern code. For example:</p><ul><li>The source code can only be written in ESM, where non-ESM dependencies need to be <a href="./dep-pre-bundling">pre-bundled as ESM</a> in order to work.</li><li>Web workers are encouraged to be written with the <a href="./features#web-workers"><code>new Worker</code> syntax</a> to follow modern standards.</li><li>Node.js modules cannot be used in the browser.</li></ul><p>When adding new features, these patterns are followed to create a future-proof API, which may not always be compatible with other build tools.</p><h2 id="a-pragmatic-approach-to-performance" tabindex="-1">A Pragmatic Approach to Performance <a class="header-anchor" href="#a-pragmatic-approach-to-performance" aria-label="Permalink to “A Pragmatic Approach to Performance”">​</a></h2><p>Vite has been focused on performance since its <a href="./why">origins</a>. Its dev server architecture allows HMR that stays fast as projects scale. Vite is based on native tools that include the <a href="https://oxc.rs/" target="_blank" rel="noreferrer">Oxc toolchain</a> and <a href="https://rolldown.rs/" target="_blank" rel="noreferrer">Rolldown</a> to implement intensive tasks but keeps the rest of the code in JS to balance speed with flexibility. When needed, framework plugins will tap into <a href="https://babeljs.io/" target="_blank" rel="noreferrer">Babel</a> to compile user code. Thanks to Rolldown&#39;s Rollup plugin compatibility, Vite has access to a wide ecosystem of plugins.</p><h2 id="building-frameworks-on-top-of-vite" tabindex="-1">Building Frameworks on Top of Vite <a class="header-anchor" href="#building-frameworks-on-top-of-vite" aria-label="Permalink to “Building Frameworks on Top of Vite”">​</a></h2><p>Although Vite can be used by users directly, it shines as a tool to create frameworks. Vite core is framework agnostic, but there are polished plugins for each UI framework. Its <a href="./api-javascript">JS API</a> allows App Framework authors to use Vite features to create tailored experiences for their users. Vite includes support for <a href="./ssr">SSR primitives</a>, usually present in higher-level tools but fundamental to building modern web frameworks. And Vite plugins complete the picture by offering a way to share between frameworks. Vite is also a great fit when paired with <a href="./backend-integration">Backend frameworks</a> like <a href="https://vite-ruby.netlify.app/" target="_blank" rel="noreferrer">Ruby</a> and <a href="https://laravel.com/docs/vite" target="_blank" rel="noreferrer">Laravel</a>.</p><h2 id="an-active-ecosystem" tabindex="-1">An Active Ecosystem <a class="header-anchor" href="#an-active-ecosystem" aria-label="Permalink to “An Active Ecosystem”">​</a></h2><p>Vite evolution is a cooperation between framework and plugin maintainers, users, and the Vite team. We encourage active participation in Vite&#39;s Core development once a project adopts Vite. We work closely with the main projects in the ecosystem to minimize regressions on each release, aided by tools like <a href="https://github.com/vitejs/vite-ecosystem-ci" target="_blank" rel="noreferrer">vite-ecosystem-ci</a>. It allows us to run the CI of major projects using Vite on selected PRs and gives us a clear status of how the Ecosystem would react to a release. We strive to fix regressions before they hit users and allow projects to update to the next versions as soon as they are released. If you are working with Vite, we invite you to join <a href="https://chat.vite.dev" target="_blank" rel="noreferrer">Vite&#39;s Discord</a> and get involved in the project too.</p>`,14)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};